mod bincode_v1 {
    use super::*;

    pub fn save_preferences(path: &Path, preferences: &UserPreferences) -> Result<(), CacheError> {
        preferences.validate()?;

        let config = bincode::options()
            .with_limit(MAX_SERIALIZED_SIZE)
            .with_little_endian()
            .with_fixint_encoding();

        let encoded = config.serialize(preferences)?;

        let temp_path = path.with_extension("cache.tmp");
        fs::write(&temp_path, &encoded)?;
        fs::rename(&temp_path, path)?;

        Ok(())
    }

    pub fn load_preferences(path: &Path) -> Result<UserPreferences, CacheError> {
        let metadata = fs::metadata(path)?;
        if metadata.len() > MAX_SERIALIZED_SIZE {
            return Err(CacheError::Validation(format!(
                "Cache file size {} exceeds maximum of {} bytes",
                metadata.len(),
                MAX_SERIALIZED_SIZE
            )));
        }

        let data = fs::read(path)?;

        let config = bincode::options()
            .with_limit(MAX_SERIALIZED_SIZE)
            .with_little_endian()
            .with_fixint_encoding();

        let preferences: UserPreferences = config.deserialize(&data)?;

        // CRITICAL: Always validate after deserialization
        preferences.validate()?;

        Ok(preferences)
    }
}

