    prefs.display.theme = Theme::Custom("Solarized".to_string());
    prefs.display.font_size = 16;
    prefs.display.tab_width = 2;
    prefs.notifications.email_enabled = true;
    prefs.notifications.push_enabled = false;
    prefs.notifications.quiet_hours_start = Some(22);
    prefs.notifications.quiet_hours_end = Some(8);
    prefs.accessibility.high_contrast = true;
    prefs.custom_key_bindings.push(KeyBinding {
        action: "save".to_string(),
        keys: "Ctrl+S".to_string(),
    });
    prefs.custom_key_bindings.push(KeyBinding {
        action: "find".to_string(),
        keys: "Ctrl+F".to_string(),
    });
    prefs
        .recent_files
        .push("/home/alice/project/main.rs".to_string());
    prefs
        .recent_files
        .push("/home/alice/project/lib.rs".to_string());
    prefs
        .custom_settings
        .insert("auto_save_interval".to_string(), "300".to_string());
    prefs
        .custom_settings
        .insert("max_undo_history".to_string(), "100".to_string());

    // Save to disk
    println!("Saving preferences for user: {}", prefs.username);
    cache.save_v1(&prefs)?;
    println!("Preferences saved successfully.");

    // Load from disk
    println!("\nLoading preferences for user: alice");
    let loaded_prefs = cache.load_v1("alice")?;
    println!("Loaded preferences: {:#?}", loaded_prefs);

    // Verify round-trip
    assert_eq!(prefs, loaded_prefs);
    println!("\nRound-trip verification: PASSED");

    // List cached users
    let users = cache.list_cached_users()?;
    println!("\nCached users: {:?}", users);

    // Check existence
    println!(
        "Cache exists for 'alice': {}",
        cache.exists("alice")?
    );
    println!(
        "Cache exists for 'bob': {}",
        cache.exists("bob")?
    );

    // Create another user
    let mut bob_prefs = UserPreferences::new("bob".to_string());
    bob_prefs.language = Language::Spanish;
    bob_prefs.display.theme = Theme::Light;
    bob_prefs.display.font_size = 12;
    cache.save_v1(&bob_prefs)?;
    println!("\nSaved preferences for bob.");

    let users = cache.list_cached_users()?;
    println!("Cached users: {:?}", users);

    // Demonstrate validation catches bad data
    println!("\n--- Validation Tests ---");

    let mut bad_prefs = UserPreferences::new("test".to_string());
    bad_prefs.display.font_size = 100; // Invalid: exceeds max of 72
    match bad_prefs.validate() {
        Err(CacheError::Validation(msg)) => {
            println!("Caught validation error (expected): {}", msg);
        }
        _ => println!("ERROR: Should have caught validation error!"),
    }

    let mut bad_prefs2 = UserPreferences::new("test".to_string());
    bad_prefs2.display.tab_width = 0; // Invalid: must be >= 1
    match bad_prefs2.validate() {
        Err(CacheError::Validation(msg)) => {
            println!("Caught validation error (expected): {}", msg);
        }
        _ => println!("ERROR: Should have caught validation error!"),
    }

    let mut bad_prefs3 = UserPreferences::new("test".to_string());
    bad_prefs3.notifications.quiet_hours_start = Some(25); // Invalid hour
    match bad_prefs3.validate() {
        Err(CacheError::Validation(msg)) => {
            println!("Caught validation error (expected): {}", msg);
        }
        _ => println!("ERROR: Should have caught validation error!"),
    }

    // Clean up
    cache.delete("alice")?;
