    #[test]
    fn test_validation_wrong_version() {
        let mut prefs = UserPreferences::new("test".to_string());
        prefs.version = 999;
        assert!(prefs.validate().is_err());
    }

    #[test]
    fn test_validation_rejects_bad_data_on_load() {
        let (cache, _dir) = create_test_cache();

        // Save valid preferences first
        let prefs = sample_preferences();
        cache.save_v1(&prefs).unwrap();

        // Tamper with the file to create invalid data
        // We'll write a struct with an invalid version directly
        let mut bad_prefs = sample_preferences();
        bad_prefs.version = 999;

        let path = cache.cache_file_path("testuser").unwrap();
        let config = bincode::options()
            .with_limit(MAX_SERIALIZED_SIZE)
            .with_little_endian()
            .with_fixint_encoding();
        let encoded = config.serialize(&bad_prefs).unwrap();
        fs::write(&path, &encoded).unwrap();

        // Loading should fail validation
        let result = cache.load_v1("testuser");
        assert!(result.is_err());
        match result {
            Err(CacheError::Validation(msg)) => {
                assert!(msg.contains("version"));
            }
            other => panic!("Expected validation error, got: {:?}", other),
        }
    }

    #[test]
    fn test_path_traversal_prevention() {
        let (cache, _dir) = create_test_cache();
        // Characters like ../ get sanitized to __/
        let result = cache.cache_file_path("../../../etc/passwd");
        // Should succeed but the path should be sanitized
        assert!(result.is_ok());
        let path = result.unwrap();
        assert!(!path.to_string_lossy().contains(".."));
    }

    #[test]
    fn test_all_themes() {
        let (cache, _dir) = create_test_cache();

        for theme in [
            Theme::Light,
            Theme::Dark,
            Theme::Custom("Nord".to_string()),
        ] {
            let mut prefs = UserPreferences::new("themetest".to_string());
            prefs.display.theme = theme.clone();
            cache.save_v1(&prefs).unwrap();
            let loaded = cache.load_v1("themetest").unwrap();
            assert_eq!(loaded.display.theme, theme);
        }
    }

    #[test]
    fn test_all_languages() {
        let (cache, _dir) = create_test_cache();

        for lang in [
            Language::English,
            Language::Spanish,
            Language::French,
            Language::German,
            Language::Japanese,
            Language::Chinese,
            Language::Other("Korean".to_string()),
        ] {
            let mut prefs = UserPreferences::new("langtest".to_string());
            prefs.language = lang.clone();
            cache.save_v1(&prefs).unwrap();
            let loaded = cache.load_v1("langtest").unwrap();
            assert_eq!(loaded.language, lang);
        }
    }

    #[test]
    fn test_overwrite_existing_cache() {
        let (cache, _dir) = create_test_cache();

        let mut prefs = UserPreferences::new("overwrite_test".to_string());
        prefs.display.font_size = 12;
        cache.save_v1(&prefs).unwrap();

        prefs.display.font_size = 18;
        cache.save_v1(&prefs).unwrap();

        let loaded = cache.load_v1("overwrite_test").unwrap();
        assert_eq!(loaded.display.font_size, 18);
    }

    #[test]
    fn test_empty_key_binding_action() {
        let mut prefs = UserPreferences::new("test".to_string());
        prefs.custom_key_bindings.push(KeyBinding {
            action: "".to_string(),
            keys: "Ctrl+X".to_string(),
        });
        assert!(prefs.validate().is_err());
    }

